+/*
+ * Add a directory entry for (name, child_inum) into directory dir_inum.
+ * Reuses a free slot (inum==0) if available, else appends.
+ * Returns 0 on success, ERROR on failure.
+ */
+static int
+dir_add(int dir_inum, const char *name, int namelen, int child_inum)
+{
+    struct inode *dir_ip = get_inode(dir_inum);
+    int total = dir_ip->size;
+    int pos = 0;
+
+    if (namelen <= 0) namelen = (int)strlen(name);
+    if (namelen > DIRNAMELEN) return ERROR;
+
+    /* Search for a free slot */
+    while (pos < total) {
+        int bidx = pos / BLOCKSIZE;
+        int off  = pos % BLOCKSIZE;
+        int blk  = get_file_blocknum(dir_ip, bidx);
+        if (blk == 0) { pos += BLOCKSIZE - off; continue; }
+        char *bdata = get_block(blk);
+        while (off + (int)sizeof(struct dir_entry) <= BLOCKSIZE
+               && pos < total) {
+            struct dir_entry *de = (struct dir_entry *)(bdata + off);
+            if (de->inum == 0) {
+                /* Reuse this free slot */
+                memset(de, 0, sizeof(struct dir_entry));
+                de->inum = (short)child_inum;
+                memcpy(de->name, name, namelen);
+                mark_block_dirty(blk);
+                return 0;
+            }
+            off += sizeof(struct dir_entry);
+            pos += sizeof(struct dir_entry);
+        }
+        if (off < BLOCKSIZE && pos < total) pos += BLOCKSIZE - off;
+    }
