+/* =========================================================================
+ * Path resolution (namei)
+ * ========================================================================= */
+
+/*
+ * Parse next path component from *path into component[].
+ * Advances *path past the component and any following slashes.
+ * Returns length of component (0 = done, end of path).
+ */
+static int
+next_component(const char **path, char *component)
+{
+    /* skip leading slashes */
+    while (**path == '/') (*path)++;
+    if (**path == '\0') return 0;
+
+    int len = 0;
+    while (**path != '/' && **path != '\0') {
+        if (len < DIRNAMELEN)
+            component[len] = **path;
+        len++;
+        (*path)++;
+    }
+    if (len < DIRNAMELEN) component[len] = '\0';
+    else component[DIRNAMELEN] = '\0';
+
+    /* Skip trailing slashes — if there are trailing slashes, treat as "." */
+    /* Note: we handle trailing slash in namei by detecting empty component */
+    return len;
+}
+
+#define NAMEI_LOOKUP   0  /* don't follow last symlink (for unlink, link, readlink) */
+#define NAMEI_FOLLOW   1  /* follow last symlink (open, create, chdir, stat) */
+
+/*
+ * Resolve a path to an inode number.
+ *
+ *   cwd:        inode of current working directory
+ *   path:       the pathname to resolve
+ *   parent_out: if non-NULL, receives the parent directory inode
+ *   last_name:  if non-NULL, receives the last path component name
+ *   last_namelen: receives length of last_name
+ *   follow:     NAMEI_FOLLOW or NAMEI_LOOKUP for final component symlink
+ *   depth:      symlink recursion depth (caller passes 0)
+ *
+ * Returns inode number on success, or 0 on "not found",
+ * or ERROR (-1) on hard error.
+ */
+static int
+namei(int cwd, const char *path, int *parent_out,
+      char *last_name, int *last_namelen,
+      int follow, int depth)
+{
+    int cur_inum;
+    char component[DIRNAMELEN + 1];
+    const char *p = path;
+    int child_inum;
+    int prev_inum;
+
+    if (path == NULL || path[0] == '\0') return ERROR;
+    if (depth > MAXSYMLINKS) return ERROR;
+
+    /* Start from root or cwd */
+    if (path[0] == '/') {
+        cur_inum = ROOTINODE;
+        /* skip leading slashes */
+        while (*p == '/') p++;
+        if (*p == '\0') {
+            /* path is just "/" or "//..." */
+            if (parent_out) *parent_out = ROOTINODE;
+            if (last_name) { last_name[0] = '.'; last_name[1] = '\0'; }
+            if (last_namelen) *last_namelen = 1;
+            if (follow == NAMEI_FOLLOW) return ROOTINODE;
+            return ROOTINODE;
+        }
+    } else {
+        cur_inum = cwd;
+    }
